// ------------------------------------------------------------------
// 3. AUTO-INJECT REAL PAGES INTO bookDatabase AFTER DOM IS READY
//    NOTE: bookDatabase must be declared with "var" in Library.html
//    so it is accessible here on the global window scope.
// ------------------------------------------------------------------
document.addEventListener('DOMContentLoaded', function () {
  if (typeof bookDatabase === 'undefined') return;

  var idMap = {
    "enchanted-forest-secret": "enchanted-forest"
  };

  Object.keys(storyDatabase).forEach(function (storyId) {
    var bookId = idMap[storyId] || storyId;
    if (bookDatabase[bookId]) {
      if (!bookDatabase[bookId].externalLink) {
        bookDatabase[bookId].pages = storyDatabase[storyId].pages;
      }
    }
  });
});